def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            if capacity == 0 and item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        penalty = 0.0
        extra_penalty = 0.0
        hyper_penalty = 0.0
        if item == 0:
            priorities[i] = 0
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 5:
            for k in range(1, 8):
                penalty += (ratio ** (4 * k)) / (k ** 4 + 1)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j + 5))
            score = (ratio ** 6) / 3 + penalty
            if item > capacity * 6:
                score *= 5
            elif item > capacity * 5:
                score *= 4
            else:
                score *= 3
            for m in range(1, 5):
                hyper_penalty += np.sin(ratio * m) / (m + 1)
            score += abs(hyper_penalty) * 2
            priorities[i] = score * decay
        elif 3 < ratio <= 5:
            for x in range(1, 10):
                sign = (-1) ** (x + 1)
                score += sign * (ratio ** x) / (x + 3)
            for y in range(1, 6):
                decay *= (1 - 1 / (y + ratio + 4))
            score = abs(score) * decay * 15
            if 4 <= ratio <= 4.5:
                extra_penalty = 0
                for n in range(1, 8):
                    extra_penalty += (np.cos(ratio * n) + 1) / (n + 2)
                score += extra_penalty * 3
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 6)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 5)
                else:
                    temp += (ratio ** p) / (p * 4)
            multiplier = 30 if ratio < 2.2 else 20 if ratio < 2.7 else 12
            score = abs(temp) * multiplier
            if ratio > 2.8:
                extra = 0
                for m in range(1, 7):
                    extra += (ratio ** m) / (m + 4)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for p in range(1, 20):
                if p % 5 == 0:
                    temp_score -= (ratio ** p) / (p * 7)
                elif p % 4 == 0:
                    temp_score += (ratio ** p) / (p * 3)
                else:
                    temp_score += (ratio ** p) / (p * 5)
            multiplier = 28 if ratio < 1.3 else 18 if ratio < 1.7 else 9
            score = abs(temp_score) * multiplier
            if 1.8 < ratio <= 2:
                extra_penalty = 0
                for n in range(1, 9):
                    extra_penalty += (ratio ** n) / (n + 3)
                score += extra_penalty * 4
            priorities[i] = score
        elif 0 < ratio <= 1:
            val_score = 0
            for p in range(1, 18):
                if p % 6 == 0:
                    val_score += (ratio ** p) / (p * 2)
                elif p % 3 == 0:
                    val_score -= (ratio ** p) / (p * 6)
                else:
                    val_score += (ratio ** p) / (p * 4)
            if ratio < 0.15:
                multiplier = 35
            elif ratio < 0.3:
                multiplier = 25
            elif ratio < 0.5:
                multiplier = 18
            elif ratio < 0.7:
                multiplier = 10
            else:
                multiplier = 7
            score = abs(val_score) * multiplier
            if ratio > 0.9:
                extra_penalty = 0
                for n in range(1, 10):
                    extra_penalty += (ratio ** n) / (n + 2)
                score += extra_penalty * 3
            priorities[i] = score
        else:
            if ratio == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and capacity > 0:
            adjust_factor = 1.0
            for z in range(1, 6):
                adjust_factor *= (1 + z / (capacity + 2)) ** 0.5
            priorities[i] *= adjust_factor
            if (i % 2 == 0) and (item > capacity / 2):
                priorities[i] *= 1.1
            elif (i % 3 == 0) and (item < capacity / 3):
                priorities[i] *= 0.9
            mod_factor = np.tanh(priorities[i] / (capacity + 1))
            priorities[i] *= (1 + mod_factor)
    return priorities
